51		let acceptance = $state(untrack(() => bead?.acceptance ?? ''));
52		let notes = $state(untrack(() => bead?.notes ?? ''));
53		let submitting = $state(false);
54		let error = $state<string | null>(null);
55	
56		const CREATE_MUTATION = gql`
57			mutation BeadCreate($input: BeadInput!) {
58				beadCreate(input: $input) {
59					id title status priority issueType owner createdAt createdBy updatedAt labels parent description acceptance notes
60					dependencies { issueId dependsOnId type createdAt createdBy }
61				}
62			}
63		`;
64	
65		const UPDATE_MUTATION = gql`
66			mutation BeadUpdate($id: ID!, $input: BeadUpdateInput!) {
67				beadUpdate(id: $id, input: $input) {
68					id title status priority issueType owner createdAt createdBy updatedAt labels parent description acceptance notes
69					dependencies { issueId dependsOnId type createdAt createdBy }
70				}
71			}
72		`;
73	
74		async function handleSubmit(e: SubmitEvent) {
